// Allowlisted transaction types
const ALLOWED_TRANSACTION_TYPES = new Set([
  "credit",
  "debit",
  "transfer",
  "refund",
  "adjustment",
]);

// Allowlisted currency codes (ISO 4217)
const ALLOWED_CURRENCIES = new Set([
  "USD", "EUR", "GBP", "JPY", "CAD", "AUD", "CHF",
]);

// Allowlisted account status values
const VALID_ACCOUNT_STATUSES = new Set(["active"]);

